cookies = json.loads(json_data)

with open('/Users/greg/.gemini/antigravity/scratch/cookies.txt', 'w') as f:
    f.write("# Netscape HTTP Cookie File\n")
    f.write("# This file is generated by a python script.\n\n")
    for cookie in cookies:
        domain = cookie.get('domain', '')
        # Initial dot is optional in some interpretations but good for "domain" matches
        # hostOnly check: if true, the domain should not start with dot (?) 
        # Actually aria2 usually handles domains starting with dot fine.
        
        flag = 'TRUE' if cookie.get('hostOnly') == False else 'FALSE' 
        # Note: In Netscape format, the second column is "flag - TRUE if a domain cookie, FALSE if a host cookie". 
        # However, many tools output TRUE indiscriminately. Let's try to follow the meaning:
        # If domain starts with '.', it's usually treated as a domain cookie -> TRUE.
        if domain.startswith('.'):
            flag = 'TRUE'
        else:
            flag = 'FALSE'
            
        path = cookie.get('path', '/')
        secure = 'TRUE' if cookie.get('secure', False) else 'FALSE'
        expiration = str(int(cookie.get('expirationDate', 0)))
        name = cookie.get('name', '')
        value = cookie.get('value', '')
        
        f.write(f"{domain}\t{flag}\t{path}\t{secure}\t{expiration}\t{name}\t{value}\n")
print(f"Successfully converted {len(cookies)} cookies to Netscape format.")
